frobenius_norm.metal_source:
// frobenius_norm: ||x||_F = sqrt(sum(x*x)). Output (1,). Single TG, N=1M.
// float4 grid-stride loop, simd_sum, cross-simd reduce.
#include <metal_stdlib>
using namespace metal;

kernel void frobenius_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    threadgroup float reduce[32];

    device const float4* x4 = reinterpret_cast<device const float4*>(x);
    const uint N4 = N >> 2;

    float s0 = 0.0f, s1 = 0.0f, s2 = 0.0f, s3 = 0.0f;
    uint i = tid;
    const uint stride4 = TG * 4;
    for (; i + 3*TG < N4; i += stride4) {
        float4 a = x4[i];
        float4 b = x4[i + TG];
        float4 c = x4[i + 2*TG];
        float4 d = x4[i + 3*TG];
        s0 += dot(a, a);
        s1 += dot(b, b);
        s2 += dot(c, c);
        s3 += dot(d, d);
    }
    for (; i < N4; i += TG) {
        float4 v = x4[i];
        s0 += dot(v, v);
    }
    float s = (s0 + s1) + (s2 + s3);
    s = simd_sum(s);
    if ((tid & 31) == 0) reduce[tid >> 5] = s;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        s = reduce[tid];
        s = simd_sum(s);
        if (tid == 0) y[0] = sqrt(s);
    }
}

max_pool1d.metal_source:
// max_pool1d: NLC. y[n, l2, c] = max over window x[n, l2*s .. l2*s+k-1, c].
#include <metal_stdlib>
using namespace metal;

kernel void max_pool1d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   L       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   K       [[buffer(5)]],
    constant     uint&   stride  [[buffer(6)]],
    uint tid [[thread_position_in_grid]])
{
    const uint L2 = (L - K) / stride + 1;
    const uint total = N * L2 * C;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint n = idx / (L2 * C); uint r = idx % (L2 * C);
        uint l2 = r / C; uint c = r % C;
        float m = -INFINITY;
        for (uint k = 0; k < K; ++k) {
            float v = x[(n * L + l2 * stride + k) * C + c];
            m = fmax(m, v);
        }
        y[(n * L2 + l2) * C + c] = m;
    }
}

avg_pool1d.metal_source:
// avg_pool1d: NLC. mean over window.
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool1d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   L       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   K       [[buffer(5)]],
    constant     uint&   stride  [[buffer(6)]],
    uint tid [[thread_position_in_grid]])
{
    const uint L2 = (L - K) / stride + 1;
    const uint total = N * L2 * C;
    const float inv = 1.0f / float(K);
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint n = idx / (L2 * C); uint r = idx % (L2 * C);
        uint l2 = r / C; uint c = r % C;
        float s = 0.0f;
        for (uint k = 0; k < K; ++k) s += x[(n * L + l2 * stride + k) * C + c];
        y[(n * L2 + l2) * C + c] = s * inv;
    }
}

max_pool2d.metal_source:
// max_pool2d: NHWC. K=2, stride=2 specialization. float4 vectorized across C.
#include <metal_stdlib>
using namespace metal;

kernel void max_pool2d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   H       [[buffer(3)]],
    constant     uint&   W       [[buffer(4)]],
    constant     uint&   C       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    constant     uint&   stride  [[buffer(7)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint C4 = C / 4;
    const uint total4 = N * H2 * W2 * C4;

    const uint sW_in4 = C4;
    const uint sH_in4 = W * C4;
    const uint sN_in4 = H * W * C4;

    device const float4* x4 = (device const float4*)x;
    device       float4* y4 = (device       float4*)y;

    for (uint idx = tid; idx < total4; idx += 64 * 1024) {
        uint q = idx;
        uint c4 = q % C4;      q /= C4;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      uint n = q / H2;

        uint base = n * sN_in4 + (h2 * stride) * sH_in4 + (w2 * stride) * sW_in4 + c4;

        float4 v00 = x4[base];
        float4 v01 = x4[base + sW_in4];
        float4 v10 = x4[base + sH_in4];
        float4 v11 = x4[base + sH_in4 + sW_in4];

        y4[idx] = fmax(fmax(v00, v01), fmax(v10, v11));
    }
}

max_pool3d.metal_source:
// max_pool3d: NDHWC. K=2, stride=2 specialization.
#include <metal_stdlib>
using namespace metal;

kernel void max_pool3d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   C       [[buffer(6)]],
    constant     uint&   K       [[buffer(7)]],
    constant     uint&   stride  [[buffer(8)]],
    uint tid [[thread_position_in_grid]])
{
    const uint D2 = (D - K) / stride + 1;
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint total = N * D2 * H2 * W2 * C;

    // Strides (in elements) into input tensor x of shape (N, D, H, W, C)
    const uint sW_in = C;
    const uint sH_in = W * C;
    const uint sD_in = H * W * C;
    const uint sN_in = D * H * W * C;

    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint c  = q % C;       q /= C;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      q /= H2;
        uint d2 = q % D2;      uint n = q / D2;

        uint base = n * sN_in + (d2 * stride) * sD_in + (h2 * stride) * sH_in + (w2 * stride) * sW_in + c;

        // K=2 unrolled
        float v000 = x[base];
        float v001 = x[base + sW_in];
        float v010 = x[base + sH_in];
        float v011 = x[base + sH_in + sW_in];
        float v100 = x[base + sD_in];
        float v101 = x[base + sD_in + sW_in];
        float v110 = x[base + sD_in + sH_in];
        float v111 = x[base + sD_in + sH_in + sW_in];

        float m = fmax(fmax(fmax(v000, v001), fmax(v010, v011)),
                       fmax(fmax(v100, v101), fmax(v110, v111)));

        y[idx] = m;
    }
}

avg_pool2d.metal_source:
// avg_pool2d: NHWC. K=2, stride=2. float4 along C dim.
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool2d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   H       [[buffer(3)]],
    constant     uint&   W       [[buffer(4)]],
    constant     uint&   C       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    constant     uint&   stride  [[buffer(7)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint C4 = C >> 2;
    const uint total4 = N * H2 * W2 * C4;
    const float inv = 1.0f / float(K * K);

    const uint sW_in = C;
    const uint sH_in = W * C;
    const uint sN_in = H * W * C;

    for (uint idx = tid; idx < total4; idx += 64 * 1024) {
        uint q = idx;
        uint c4 = q % C4;      q /= C4;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      uint n = q / H2;

        uint base = n * sN_in + (h2 * stride) * sH_in + (w2 * stride) * sW_in + (c4 << 2);

        float4 v00 = *reinterpret_cast<const device float4*>(x + base);
        float4 v01 = *reinterpret_cast<const device float4*>(x + base + sW_in);
        float4 v10 = *reinterpret_cast<const device float4*>(x + base + sH_in);
        float4 v11 = *reinterpret_cast<const device float4*>(x + base + sH_in + sW_in);

        float4 s = (v00 + v01) + (v10 + v11);
        *reinterpret_cast<device float4*>(y + (idx << 2)) = s * inv;
    }
}

avg_pool3d.metal_source:
// avg_pool3d: NDHWC. K=2, stride=2 specialization.
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool3d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   C       [[buffer(6)]],
    constant     uint&   K       [[buffer(7)]],
    constant     uint&   stride  [[buffer(8)]],
    uint tid [[thread_position_in_grid]])
{
    const uint D2 = (D - K) / stride + 1;
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint total = N * D2 * H2 * W2 * C;
    const float inv = 1.0f / float(K * K * K);

    const uint sW_in = C;
    const uint sH_in = W * C;
    const uint sD_in = H * W * C;
    const uint sN_in = D * H * W * C;

    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint c  = q % C;       q /= C;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      q /= H2;
        uint d2 = q % D2;      uint n = q / D2;

        uint base = n * sN_in + (d2 * stride) * sD_in + (h2 * stride) * sH_in + (w2 * stride) * sW_in + c;

        float v000 = x[base];
        float v001 = x[base + sW_in];
        float v010 = x[base + sH_in];
        float v011 = x[base + sH_in + sW_in];
        float v100 = x[base + sD_in];
        float v101 = x[base + sD_in + sW_in];
        float v110 = x[base + sD_in + sH_in];
        float v111 = x[base + sD_in + sH_in + sW_in];

        float s = (v000 + v001) + (v010 + v011) + (v100 + v101) + (v110 + v111);
        y[idx] = s * inv;
    }
}

mingpt_new_gelu.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void mingpt_new_gelu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const float k0 = 0.7978845608f;
    const float k1 = 0.044715f;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 t = k0 * (v + k1 * v * v * v);
        *reinterpret_cast<device float4*>(&y[i * 4]) = 0.5f * v * (1.0f + precise::tanh(t));
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        float t = k0 * (v + k1 * v * v * v);
        y[i] = 0.5f * v * (1.0f + precise::tanh(t));
    }
}

huber_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void huber_loss_f32(
    device const float*  pred      [[buffer(0)]],
    device const float*  target    [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  delta     [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        float r = pred[i] - target[i];
        float a = fabs(r);
        float q = 0.5f * r * r;
        float l = delta * (a - 0.5f * delta);
        y[i] = a <= delta ? q : l;
    }
}

triplet_margin_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void triplet_margin_loss_f32(
    device const float*  a       [[buffer(0)]],
    device const float*  p       [[buffer(1)]],
    device const float*  n       [[buffer(2)]],
    device       float*  y       [[buffer(3)]],
    constant     uint&   D       [[buffer(4)]],
    constant     float&  margin  [[buffer(5)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* ar = a + row * D;
    device const float* pr = p + row * D;
    device const float* nr = n + row * D;
    threadgroup float r1[32], r2[32];

    float sp = 0.0f, sn = 0.0f;
    for (uint i = tid; i < D; i += TG) {
        float dp = ar[i] - pr[i];
        float dn = ar[i] - nr[i];
        sp += dp * dp;
        sn += dn * dn;
    }
    sp = simd_sum(sp);
    sn = simd_sum(sn);
    if ((tid & 31) == 0) { r1[tid >> 5] = sp; r2[tid >> 5] = sn; }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sp = simd_sum(r1[tid]);
        sn = simd_sum(r2[tid]);
        if (tid == 0) y[row] = fmax(sqrt(sp) - sqrt(sn) + margin, 0.0f);
    }
}

kl_div_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void kl_div_loss_f32(
    device const float*  log_pred  [[buffer(0)]],
    device const float*  target    [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        float t = fabs(target[i]) + 1e-6f;
        float lp = -fabs(log_pred[i]);
        y[i] = t * (log(t) - lp);
    }
}

cumsum_exclusive.metal_source:
// cumsum_exclusive: per-row exclusive prefix sum. Two-level scan via simd hardware.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_exclusive_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;
    const uint sl = t & 31;

    float v = x[row * C + t];
    float local_scan = simd_prefix_inclusive_sum(v);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Inclusive total at this thread, then subtract own v to get exclusive.
    y[row * C + t] = local_scan + tg_totals[sg] - v;
}

masked_cumsum.metal_source:
// masked_cumsum: per-row cumsum(x * mask). Two-level scan.
#include <metal_stdlib>
using namespace metal;

kernel void masked_cumsum_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  m       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;
    const uint sl = t & 31;

    float v = x[row * C + t] * m[row * C + t];
    float local_scan = simd_prefix_inclusive_sum(v);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * C + t] = local_scan + tg_totals[sg];
}

conv2d_relu_bias.metal_source:
// conv2d_relu_bias: implicit im2col GEMM via simdgroup_matrix MMA + fused bias + ReLU epilogue.
// NHWC. x (N=8,H=64,W=64,C=64), w (K=128,R=3,S=3,C=64), b (K), y (N,H2=62,W2=62,K=128).
// GEMM: M_g = N*H2*W2 = 30752, N_g = K = 128, K_g = R*S*C = 576.
// Tile BM=64, BN=128, BK=16. 1024 threads = 32 simdgroups.

#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 128, BK = 16;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 1024;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 132

kernel void conv2d_relu_bias_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device const float*  b       [[buffer(2)]],
    device       float*  y       [[buffer(3)]],
    constant     uint&   N_      [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   C       [[buffer(7)]],
    constant     uint&   K_out   [[buffer(8)]],
    constant     uint&   R       [[buffer(9)]],
    constant     uint&   S       [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H2 = (H - R) + 1;
    const uint W2 = (W - S) + 1;
    const uint M_g = N_ * H2 * W2;
    const uint K_g = R * S * C;
    const uint SC  = S * C;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint total_tiles = num_m_tiles;

    threadgroup float scratch[BM * BN];
    threadgroup float* As = scratch;
    threadgroup float* Bs = scratch + BM * LDA;
    threadgroup float* Cs = scratch;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < total_tiles; tile += n_tg) {
        const uint c_row0 = tile * BM;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            {
                const uint a_row = lid / BK;
                const uint a_col = lid % BK;
                const uint m_g = c_row0 + a_row;
                const uint k_glob = k0 + a_col;
                float v = 0.0f;
                if (m_g < M_g && k_glob < K_g) {
                    const uint rr = k_glob / SC;
                    const uint rem = k_glob - rr * SC;
                    const uint ss = rem / C;
                    const uint c  = rem - ss * C;
                    const uint n_idx = m_g / (H2 * W2);
                    const uint hw = m_g - n_idx * (H2 * W2);
                    const uint h2 = hw / W2;
                    const uint w2 = hw - h2 * W2;
                    const uint hi = h2 + rr;
                    const uint wi = w2 + ss;
                    v = x[((n_idx * H + hi) * W + wi) * C + c];
                }
                As[a_row * LDA + a_col] = v;
            }
            #pragma unroll
            for (uint p = 0; p < 2; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint b_col = t / BK;
                const uint b_row = t % BK;
                const uint k_glob = k0 + b_row;
                const uint n_col = b_col;
                float v = 0.0f;
                if (k_glob < K_g && n_col < K_out) {
                    v = w[n_col * K_g + k_glob];
                }
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Epilogue: add bias, ReLU, store. Each thread stores 1 row × 4 cols (float4).
        // 1024 threads / (BN/4=32 cols) = 32 rows per pass; 64 rows → 2 passes.
        {
            #pragma unroll
            for (uint rs = 0; rs < 2; ++rs) {
                const uint r = (lid / 32u) + rs * 32u;
                const uint cq = lid % 32u;
                const uint c = cq * 4u;
                const uint m_g = c_row0 + r;
                if (m_g < M_g) {
                    const uint n_idx = m_g / (H2 * W2);
                    const uint hw = m_g - n_idx * (H2 * W2);
                    const uint h2 = hw / W2;
                    const uint w2 = hw - h2 * W2;
                    float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                    float4 bv = *reinterpret_cast<device const float4*>(&b[c]);
                    v += bv;
                    v = fmax(v, float4(0.0f));
                    *reinterpret_cast<device float4*>(&y[((n_idx * H2 + h2) * W2 + w2) * K_out + c]) = v;
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

matmul_sub_mul_relu.metal_source:
// matmul_sub_mul_relu: y = ReLU((x @ w - sub_val) * mul_val).
// 64x64 MMA tile, BK=16, 256 thr/tg, double-buffered, padded.
// Grid 65536x1x1 → 256 TGs; only 16 active (4x4 tile grid).
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;
constant constexpr uint TILES_N = 256 / BN;
constant constexpr uint ACTIVE_TG = TILES_N * (256 / BM);

kernel void matmul_sub_mul_relu_f32(
    device const float* X       [[buffer(0)]],
    device const float* W       [[buffer(1)]],
    device       float* Y       [[buffer(2)]],
    constant     uint&  M       [[buffer(3)]],
    constant     uint&  N       [[buffer(4)]],
    constant     uint&  K       [[buffer(5)]],
    constant     float& sub_val [[buffer(6)]],
    constant     float& mul_val [[buffer(7)]],
    uint tgid_lin               [[threadgroup_position_in_grid]],
    uint sgid                   [[simdgroup_index_in_threadgroup]],
    uint lid                    [[thread_index_in_threadgroup]],
    uint lane                   [[thread_index_in_simdgroup]])
{
    if (tgid_lin >= ACTIVE_TG) return;
    const uint tx = tgid_lin % TILES_N;
    const uint ty = tgid_lin / TILES_N;

    // Shared scratch: holds As[2] + Bs[2] during matmul (4736 floats),
    // reused as Cs (BM*BN = 4096 floats) for fused epilogue.
    constexpr uint AS_SZ = 2 * BM * LDA;        // 2560
    constexpr uint BS_SZ = 2 * BK * LDB;        // 2176
    constexpr uint CS_SZ = BM * BN;             // 4096
    constexpr uint SCRATCH = (AS_SZ + BS_SZ > CS_SZ) ? (AS_SZ + BS_SZ) : CS_SZ;
    threadgroup float scratch[SCRATCH];
    threadgroup float (*As)[BM * LDA] = reinterpret_cast<threadgroup float(*)[BM * LDA]>(&scratch[0]);
    threadgroup float (*Bs)[BK * LDB] = reinterpret_cast<threadgroup float(*)[BK * LDB]>(&scratch[AS_SZ]);
    threadgroup float* Cs = &scratch[0];

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;
    const uint c_col0 = tx * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = K / BK;
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }

    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    // Need a barrier before reusing scratch as Cs (matmul read As/Bs from it).
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Store accumulators into shared scratch (Cs), then apply fused
    // epilogue (sub→mul→ReLU) with vectorized device writes.
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &Cs[(sm * SM + i * 8) * BN + (sn * SN + j * 8)],
                            BN);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint total_f4 = BM * BN / 4;
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
        float4 out = (v - sub_val) * mul_val;
        out = fmax(out, float4(0.0f));
        *reinterpret_cast<device float4*>(&Y[(c_row0 + r) * N + c_col0 + c]) = out;
    }
}

conv_transpose2d_clamp_scale_div.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void conv_transpose2d_clamp_scale_div_f32(
    device const float* x      [[buffer(0)]],
    device const float* w      [[buffer(1)]],
    device const float* b      [[buffer(2)]],
    device       float* y      [[buffer(3)]],
    constant     uint&  N      [[buffer(4)]],
    constant     uint&  C_in   [[buffer(5)]],
    constant     uint&  H      [[buffer(6)]],
    constant     uint&  W      [[buffer(7)]],
    constant     uint&  C_out  [[buffer(8)]],
    constant     uint&  R      [[buffer(9)]],
    constant     uint&  stride [[buffer(10)]],
    constant     float& scale  [[buffer(11)]],
    constant     float& div    [[buffer(12)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H_out = (H - 1) * stride + R;
    const uint W_out = (W - 1) * stride + R;
    const uint total = N * H_out * W_out * C_out;
    const float inv_div = 1.0f / div;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint k = q % C_out; q /= C_out;
        uint w_out = q % W_out; q /= W_out;
        uint h_out = q % H_out; uint n = q / H_out;
        float sum = b[k];
        for (uint r = 0; r < R; ++r) {
            int hi_s = int(h_out) - int(r);
            if (hi_s < 0 || hi_s % int(stride) != 0) continue;
            uint hi = uint(hi_s) / stride;
            if (hi >= H) continue;
            for (uint s = 0; s < R; ++s) {
                int wi_s = int(w_out) - int(s);
                if (wi_s < 0 || wi_s % int(stride) != 0) continue;
                uint wi = uint(wi_s) / stride;
                if (wi >= W) continue;
                for (uint c = 0; c < C_in; ++c)
                    sum += x[((n * H + hi) * W + wi) * C_in + c]
                         * w[((k * R + r) * R + s) * C_in + c];
            }
        }
        sum = clamp(sum, -1.0f, 1.0f) * scale;
        y[idx] = clamp(sum, -1.0f, 1.0f) * inv_div;
    }
}

conv3d_multi_act_bias.metal_source:
#include <metal_stdlib>
using namespace metal;

static inline float gelu_erf_poly(float x) {
    const float k = 0.70710678f;
    float z = x * k;
    float t = 1.0f / (1.0f + 0.3275911f * fabs(z));
    float y = 1.0f - (((((1.061405429f * t - 1.453152027f) * t)
              + 1.421413741f) * t - 0.284496736f) * t + 0.254829592f)
              * t * exp(-z * z);
    float erfz = copysign(y, z);
    return 0.5f * x * (1.0f + erfz);
}

kernel void conv3d_multi_act_bias_f32(
    device const float* x [[buffer(0)]],
    device const float* w [[buffer(1)]],
    device const float* b [[buffer(2)]],
    device       float* y [[buffer(3)]],
    constant     uint& N  [[buffer(4)]],
    constant     uint& C  [[buffer(5)]],
    constant     uint& D  [[buffer(6)]],
    constant     uint& H  [[buffer(7)]],
    constant     uint& W  [[buffer(8)]],
    constant     uint& K  [[buffer(9)]],
    constant     uint& R  [[buffer(10)]],
    uint tid [[thread_position_in_grid]])
{
    const uint D2 = D - R + 1, H2 = H - R + 1, W2 = W - R + 1;
    const uint total = N * D2 * H2 * W2 * K;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint k = q % K; q /= K;
        uint w2 = q % W2; q /= W2;
        uint h2 = q % H2; q /= H2;
        uint d2 = q % D2; uint n = q / D2;
        float sum = 0.0f;
        for (uint rd = 0; rd < R; ++rd)
            for (uint rh = 0; rh < R; ++rh)
                for (uint rw = 0; rw < R; ++rw)
                    for (uint c = 0; c < C; ++c)
                        sum += x[(((n * D + d2 + rd) * H + h2 + rh) * W + w2 + rw) * C + c]
                             * w[(((k * R + rd) * R + rh) * R + rw) * C + c];
        float v = fmax(sum, 0.0f);
        v = v > 0.0f ? v : 0.01f * v;
        v = gelu_erf_poly(v);
        v = 1.0f / (1.0f + exp(-v));
        y[idx] = v + b[k];
    }
}

conv3d_div_pool_sum.metal_source:
// Multi-TG. Each thread handles its own tile-slice. Per tile, patch is loaded
// once into TG memory (shared by threads in TG). Each thread iterates over
// all 64 k's, reading weights from global, patch from tg memory. Per-thread
// running max over k. Across threads in TG, summation via tree-reduce.
//
// To amortize: each TG processes many tiles, where threads do them in parallel
// (each thread = one tile). TG_THR=64 threads per TG → 64 tiles in parallel.
// All 64 threads share the same patch? No — they have different tiles → no
// patch sharing.
//
// Better: each TG processes ONE tile per "iteration", and TG_THR=64 threads
// all collaborate. Each thread = one k. Patch loaded into tg mem, used by
// all 64 threads. Weights are per-thread (1 k per thread), loaded from global
// per tile. Weight reuse only if tiles overlap (they do, but not naturally).
//
// Best: outer-tile, weights cached across tiles in registers per thread (1 k).
// This is the design here.
#include <metal_stdlib>
using namespace metal;

#define NBUCK 128u
#define TG_THR 64u

kernel void conv3d_div_pool_sum_f32(
    device const float* x [[buffer(0)]],
    device const float* w [[buffer(1)]],
    device       float* y [[buffer(2)]],
    constant     uint& N  [[buffer(3)]],
    constant     uint& C  [[buffer(4)]],
    constant     uint& D  [[buffer(5)]],
    constant     uint& H  [[buffer(6)]],
    constant     uint& W  [[buffer(7)]],
    constant     uint& K  [[buffer(8)]],
    constant     uint& R  [[buffer(9)]],
    constant     float& div_val  [[buffer(10)]],
    constant     float& bias_val [[buffer(11)]],
    uint3 tgid [[threadgroup_position_in_grid]],
    uint3 tg_per_grid [[threadgroups_per_grid]],
    uint  tid  [[thread_index_in_threadgroup]],
    uint  sg   [[simdgroup_index_in_threadgroup]],
    uint  lane [[thread_index_in_simdgroup]])
{
    constexpr uint Cc=32, Rc=3, Kc=64, Dc=32, Hc=32, Wc=32, Nc=4;
    constexpr uint D2=Dc-Rc+1, H2=Hc-Rc+1, W2=Wc-Rc+1;
    constexpr uint VOL    = D2*H2*W2;
    constexpr uint NTILES = Nc * VOL;
    constexpr uint PATCH  = Cc*Rc*Rc*Rc;

    const uint mytg = tgid.x;
    const uint nTGs = tg_per_grid.x;

    threadgroup float patch[PATCH];
    threadgroup float sgmax_buf[2];

    // Each thread = one k. Load this thread's weights ONCE (864 floats).
    // Use strided lane layout so we can later do simd_sum cooperative dot.
    // wreg[j] = W[k=tid, lane + 32*j] for j=0..26.
    // BUT 27 floats × 4B = 108B per thread; weights for 64 ks = 64*864 = 55K B
    // shared across all threads.
    //
    // Wait — each thread holds its OWN k's full slice (864 floats). That's
    // 864 regs × 64 threads = 55K regs per TG → 220 KB. Way too many regs.
    //
    // Trick: have each thread hold weights for its k in strided format so
    // simd_sum can cooperate. With 32 lanes per simdgroup, lane l holds
    // 27 weights of the simdgroup's k=sg+ ... no wait that's the prior design.
    //
    // Let me just stick with the simd-coop dot with running weight loads.
    // 32 passes per tile, each pass each sg loads 27 weights from global.
    // Weight bandwidth: 32*27*4 = 3.5 KB per tile per simdgroup, total per
    // tile = 7 KB. Across 108000 tiles = 740 MB. At 100 GB/s = 7.4 ms.
    //
    // PLUS patch: 3.5 KB per tile × 108000 = 380 MB → 3.8 ms.
    //
    // Total memory time ≈ 11 ms theoretical. Compute time ≈ 4 ms (computed
    // earlier). MLX 17-24 ms. So we should be able to hit ~12 ms ⇒ 2× speedup.
    //
    // The 51 ms we got is 5× memory-bound. Why? Probably because L2 isn't
    // being utilized — every TG reads the same weights and they should cache.
    // Maybe Apple's L1 per-core is small and 220 KB weights spill.

    float local_sum = 0.0f;

    const uint tiles_per_tg = (NTILES + nTGs - 1) / nTGs;
    const uint tile_lo = mytg * tiles_per_tg;
    const uint tile_hi = min(NTILES, tile_lo + tiles_per_tg);

    for (uint t = tile_lo; t < tile_hi; ++t) {
        uint w2 =  t % W2;
        uint h2 = (t / W2) % H2;
        uint d2 = (t / (W2 * H2)) % D2;
        uint n  =  t / (W2 * H2 * D2);

        threadgroup float4* p4 = (threadgroup float4*)patch;
        device const float4* x4 = (device const float4*)x;
        #pragma unroll
        for (uint ii = 0; ii < 4; ++ii) {
            uint i = tid + ii*TG_THR;
            if (i < 216) {
                uint spatial = i >> 3;
                uint cvec    = i & 7;
                uint rd = spatial / 9u;
                uint rem = spatial - rd*9u;
                uint rh = rem / 3u;
                uint rw = rem - rh*3u;
                uint x_idx = ((((n*Dc + d2 + rd)*Hc + h2 + rh)*Wc + w2 + rw)*Cc) >> 2;
                p4[i] = x4[x_idx + cvec];
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Hold per-lane patch slice.
        float p_reg[27];
        #pragma unroll
        for (uint j = 0; j < 27; ++j) p_reg[j] = patch[lane + 32u*j];

        float tile_max = -INFINITY;
        // 2 simdgroups → 2 k's per pass, 32 passes for K=64.
        for (uint pass = 0; pass < 32; ++pass) {
            uint k = pass * 2u + sg;
            const device float* wk = w + k * PATCH;
            float s = 0.0f;
            // Manually unroll inner loop 27 ways → 27 fma.
            #pragma unroll
            for (uint j = 0; j < 27; ++j) {
                s = fma(p_reg[j], wk[lane + 32u*j], s);
            }
            s = simd_sum(s);
            tile_max = max(tile_max, s);
        }

        if (lane == 0) sgmax_buf[sg] = tile_max;
        threadgroup_barrier(mem_flags::mem_threadgroup);
        float final_tile_max = max(sgmax_buf[0], sgmax_buf[1]);

        if (tid == 0) local_sum += final_tile_max;
    }

    if (tid == 0) {
        device atomic<float>* slot = (device atomic<float>*)(y + 1 + (mytg % NBUCK));
        atomic_fetch_add_explicit(slot, local_sum, memory_order_relaxed);
    }

    threadgroup_barrier(mem_flags::mem_device);

    threadgroup bool am_last;
    if (tid == 0) {
        am_last = false;
        device atomic_uint* counter = (device atomic_uint*)(y + (1 + NBUCK));
        uint prev = atomic_fetch_add_explicit(counter, 1u, memory_order_relaxed);
        if (prev + 1u == nTGs) am_last = true;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (!am_last) return;

    float fsum_local = 0.0f;
    for (uint i = tid; i < NBUCK; i += TG_THR) {
        fsum_local += y[1 + i];
    }
    float fsg = simd_sum(fsum_local);
    if (lane == 0) sgmax_buf[sg] = fsg;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid == 0) {
        float total = sgmax_buf[0] + sgmax_buf[1];
        const float final_scale = (1.0f / div_val) / float(VOL);
        y[0] = total * final_scale + float(Nc) * bias_val;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    for (uint i = tid; i < NBUCK; i += TG_THR) {
        y[1 + i] = 0.0f;
    }
    if (tid == 0) {
        device atomic_uint* counter = (device atomic_uint*)(y + (1 + NBUCK));
        atomic_store_explicit(counter, 0u, memory_order_relaxed);
    }
}

matmul_gelu_softmax.metal_source:
// matmul_gelu_softmax: y = softmax(GELU(x @ w), axis=-1)
// x (256,256), w (256,256), output (256,256). Grid (256,256,1) TG (256,1,1).
// BM=16, BN=256, BK=8. 16 TGs across 10 M4 cores. Double-buffered B.
//
// 8 simdgroups (256 threads). SIMDS_M=2, SIMDS_N=4 (SM=8, SN=64). MMA_M=1, MMA_N=8.
// Softmax: 16 threads/row, simd_shuffle_xor stride 1..8 inside a 16-lane half.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 16;
constant constexpr uint BN = 256;
constant constexpr uint BK = 16;
constant constexpr uint LDA = BK;
constant constexpr uint LDB = BN;
constant constexpr uint LDC = BN;

constant constexpr uint SIMDS_M = 2;
constant constexpr uint SIMDS_N = 4;
constant constexpr uint SM = BM / SIMDS_M;  // 8
constant constexpr uint SN = BN / SIMDS_N;  // 64
constant constexpr uint MMA_N = SN / 8;     // 8

kernel void matmul_gelu_softmax_f32(
    device const float* X [[buffer(0)]],
    device const float* W [[buffer(1)]],
    device       float* Y [[buffer(2)]],
    constant     uint&  M [[buffer(3)]],
    constant     uint&  N [[buffer(4)]],
    constant     uint&  K [[buffer(5)]],
    uint3 tgid            [[threadgroup_position_in_grid]],
    uint  sgid            [[simdgroup_index_in_threadgroup]],
    uint  lid             [[thread_index_in_threadgroup]])
{
    const uint ty = tgid.y;
    if (ty >= 16) return;

    threadgroup float As[BM * LDA];        // 16*16*4 = 1024 B
    // Bs (BK*LDB=16*256=16384 B) and Cs (BM*LDC=16*256=16384 B) overlay the
    // same TG buffer: Bs lifetime ends before Cs begins (after MMA finishes).
    threadgroup float shared_bc[BM * LDC]; // 16384 B
    threadgroup float* Bs = shared_bc;     // alias during matmul
    threadgroup float* Cs = shared_bc;     // alias after matmul

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_N];
    #pragma unroll
    for (uint j = 0; j < MMA_N; ++j)
        C_acc[j] = simdgroup_matrix<float, 8, 8>(0.0f);

    const uint num_k_tiles = K / BK;       // 32

    for (uint kt = 0; kt < num_k_tiles; ++kt) {
        const uint k0 = kt * BK;
        // A: 16 rows × 16 cols = 256 floats = 64 float4 → 64 threads.
        if (lid < 64) {
            uint ar = lid >> 2;
            uint ac4 = lid & 3;
            *reinterpret_cast<threadgroup float4*>(&As[ar * LDA + ac4 * 4]) =
                *reinterpret_cast<const device float4*>(&X[(c_row0 + ar) * K + k0 + ac4 * 4]);
        }
        // B: 16 rows × 256 cols = 1024 float4 → 4 per thread.
        #pragma unroll
        for (uint q = 0; q < 4; ++q) {
            uint idx = q * 256 + lid;
            uint br = idx / 64;
            uint bc4 = idx % 64;
            *reinterpret_cast<threadgroup float4*>(&Bs[br * LDB + bc4 * 4]) =
                *reinterpret_cast<const device float4*>(&W[(k0 + br) * N + bc4 * 4]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk, B_blk[MMA_N];
            simdgroup_load(A_blk, &As[(sm * SM) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[j], A_blk, B_blk[j], C_acc[j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    #pragma unroll
    for (uint j = 0; j < MMA_N; ++j)
        simdgroup_store(C_acc[j], &Cs[(sm * SM) * LDC + sn * SN + j * 8], LDC);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ---- Softmax phase (same as before)
    const uint r = lid >> 4;
    const uint lane16 = lid & 15;
    const uint col_base = lane16 * 16;

    const float k_inv_sqrt2 = 0.70710678118654752f;
    float vals[16];
    float local_max = -INFINITY;

    threadgroup const float* Crow = &Cs[r * LDC + col_base];
    #pragma unroll
    for (uint t = 0; t < 16; t += 4) {
        float4 v = *reinterpret_cast<threadgroup const float4*>(Crow + t);
        float ss[4] = { v.x, v.y, v.z, v.w };
        #pragma unroll
        for (uint u = 0; u < 4; ++u) {
            float s = ss[u];
            float z = s * k_inv_sqrt2;
            float at = 1.0f / (1.0f + 0.3275911f * fabs(z));
            float yp = 1.0f - (((((1.061405429f * at - 1.453152027f) * at)
                          + 1.421413741f) * at - 0.284496736f) * at + 0.254829592f) * at * fast::exp(-z * z);
            float erfz = copysign(yp, z);
            float gv = 0.5f * s * (1.0f + erfz);
            vals[t + u] = gv;
            local_max = fmax(local_max, gv);
        }
    }
    float rmax = local_max;
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 1));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 2));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 4));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 8));

    float local_sum = 0.0f;
    #pragma unroll
    for (uint u = 0; u < 16; ++u) {
        float e = fast::exp(vals[u] - rmax);
        vals[u] = e;
        local_sum += e;
    }
    float rsum = local_sum;
    rsum += simd_shuffle_xor(rsum, 1);
    rsum += simd_shuffle_xor(rsum, 2);
    rsum += simd_shuffle_xor(rsum, 4);
    rsum += simd_shuffle_xor(rsum, 8);
    float inv = 1.0f / rsum;

    device float* Yrow = &Y[(c_row0 + r) * N + col_base];
    #pragma unroll
    for (uint t = 0; t < 16; t += 4) {
        float4 o = { vals[t]*inv, vals[t+1]*inv, vals[t+2]*inv, vals[t+3]*inv };
        *reinterpret_cast<device float4*>(Yrow + t) = o;
    }
}
